function test_base64_to_binary() {
    $exchange = new \ccxt\async\Exchange(array(
        'id' => 'sampleexchange',
    ));
    assert('GO_SKIP_START');
    // Test 1: Simple base64
    $b64_1 = 'aGVsbG8='; // hello
    $binary1 = $exchange->base64_to_binary($b64_1);
    assert($exchange->binary_to_base64($binary1) === $b64_1);
    // Test 2: Binary with space in original
    $b64_2 = 'aGVsbG8gd29ybGQ='; // hello world
    $binary2 = $exchange->base64_to_binary($b64_2);
    assert($exchange->binary_to_base64($binary2) === $b64_2);
    // Test 3: Short binary
    $b64_3 = 'dGVzdA=='; // test
    $binary3 = $exchange->base64_to_binary($b64_3);
    assert($exchange->binary_to_base64($binary3) === $b64_3);
    // Test 4: Empty binary
    $b64_4 = '';
    $binary4 = $exchange->base64_to_binary($b64_4);
    assert($exchange->binary_to_base64($binary4) === $b64_4);
    // Test 5: Single byte
    $b64_5 = 'YQ=='; // a
    $binary5 = $exchange->base64_to_binary($b64_5);
    assert($exchange->binary_to_base64($binary5) === $b64_5);
    // Test 6: Two bytes
    $b64_6 = 'YWI='; // ab
    $binary6 = $exchange->base64_to_binary($b64_6);
    assert($exchange->binary_to_base64($binary6) === $b64_6);
    // Test 7: Three bytes (no padding)
    $b64_7 = 'YWJj'; // abc
    $binary7 = $exchange->base64_to_binary($b64_7);
    assert($exchange->binary_to_base64($binary7) === $b64_7);
    // Test 8: JSON-like binary
    $b64_8 = 'eyJrZXkiOiJ2YWx1ZSJ9'; // {"key":"value"}
    $binary8 = $exchange->base64_to_binary($b64_8);
    assert($exchange->binary_to_base64($binary8) === $b64_8);
    // Test 9: Numbers as binary
    $b64_9 = 'MTIzNDU2'; // 123456
    $binary9 = $exchange->base64_to_binary($b64_9);
    assert($exchange->binary_to_base64($binary9) === $b64_9);
    // Test 10: Special characters
    $b64_10 = 'aGVsbG8rd29ybGQvdGVzdA=='; // hello+world/test
    $binary10 = $exchange->base64_to_binary($b64_10);
    assert($exchange->binary_to_base64($binary10) === $b64_10);
    assert('GO_SKIP_END');
    assert($exchange->safe_string(null, 'key') === null, 'GO_WORKAROUND');
}
